def assert_state_words_unique():
    seen = {}
    for name, addr in STATE_WORDS:
        if addr in seen:
            raise SystemExit(f'state word overlap: {seen[addr]} and {name} both use 0x{addr:x}')
        seen[addr] = name

def assert_memory_map_nonoverlap():
    ordered = sorted(MEMORY_REGIONS, key=lambda r: r[1])
    for (name, start, size), (next_name, next_start, _) in zip(ordered, ordered[1:]):
        end = start + size
        if end > next_start:
            raise SystemExit(f'memory map overlap: {name} ends 0x{end:x} > {next_name} starts 0x{next_start:x}')

def emit_chs_read_sequence(a: Asm16, start_lba: int, sectors: int, load_addr: int, boot_label: str, err_label: str):
    # BIOS INT 13h cannot DMA across a 64K ES:BX boundary, so split reads by track and boundary.
    lba = start_lba
    remaining = sectors
    addr = load_addr
    while remaining:
        track_left = 18 - (lba % 18)
        boundary_left = (0x10000 - (addr & 0xFFFF)) // 512
        if boundary_left == 0:
            boundary_left = 128
        count = min(remaining, track_left, boundary_left, 18)
        cyl = lba // 36
        head = (lba % 36) // 18
        sector = (lba % 18) + 1
        if not (0 <= cyl <= 79 and 0 <= head <= 1 and 1 <= sector <= 18):
            raise SystemExit(f'CHS out of range for lba={lba}')
        a.emit(0xB8); a.imm16(addr >> 4); a.emit(0x8E,0xC0)  # mov ax,seg; mov es,ax
        a.emit(0xBB); a.imm16(addr & 0xF)                    # mov bx,offset
        a.emit(0xB4,0x02,0xB0,count,0xB5,cyl,0xB1,sector,0xB6,head,0x8A,0x16)
        a.abs16(boot_label); a.emit(0xCD,0x13); a.emit(0x0F,0x82); a.patches.append((len(a.code), err_label, 2, 'call')); a.emit(0,0)
        lba += count
        addr += count * 512
        remaining -= count

def build_stage1():
    a=Asm16(0x7C00)
    a.emit(0xFA,0x31,0xC0,0x8E,0xD8,0x8E,0xC0,0x8E,0xD0,0xBC); a.imm16(0x7C00); a.emit(0xFB)
    for port,val in [(0x03F9,0),(0x03FB,0x80),(0x03F8,3),(0x03F9,0),(0x03FB,3),(0x03FA,0xC7),(0x03FC,0x0B)]:
        a.emit(0xBA); a.imm16(port); a.emit(0xB0,val,0xEE)
    a.emit(0xB2,0x00,0x88,0x16); a.abs16('boot_drive')
    a.emit(0xBE); a.abs16('boot_msg'); a.call('serial_print')
    a.emit(0xB4,0x00,0x8A,0x16); a.abs16('boot_drive'); a.emit(0xCD,0x13)
    emit_chs_read_sequence(a, 1, STAGE1_5_SECTORS, STAGE1_5_LOAD, 'boot_drive', 'disk_error')
    a.emit(0xEA); a.imm16(STAGE1_5_LOAD); a.imm16(0)
    a.label('disk_error'); a.emit(0xBE); a.abs16('err_msg'); a.call('serial_print')
    a.label('hang'); a.emit(0xF4); a.jmp('hang')
    add_serial_routines(a)
    a.label('boot_msg'); a.text('Fluid HTML kernel stage1 loading stage1.5\r\n')
    a.label('err_msg'); a.text('html.disk_error.stage1\r\n')
    a.label('boot_drive'); a.emit(0)
    data=bytearray(a.patch())
    if len(data) > 510:
        raise SystemExit(f'html stage1 too large {len(data)} > 510')
    data.extend(b'\0'*(510-len(data))); data.extend(b'\x55\xAA'); return bytes(data)

def build_stage1_5():
    a=Asm16(STAGE1_5_LOAD)
    a.emit(0xFA,0x31,0xC0,0x8E,0xD8,0x8E,0xC0,0x8E,0xD0,0xBC); a.imm16(0x7C00); a.emit(0xFB)
    a.emit(0xB2,0x00,0x88,0x16); a.abs16('boot_drive')
    a.emit(0xBE); a.abs16('boot_msg'); a.call('serial_print')
    a.emit(0xB4,0x00,0x8A,0x16); a.abs16('boot_drive'); a.emit(0xCD,0x13)
    emit_chs_read_sequence(a, STAGE2_LBA, STAGE2_SECTORS, STAGE2_LOAD, 'boot_drive', 'disk_error')
    emit_chs_read_sequence(a, INITRAMFS_LBA, INITRAMFS_SECTORS, INITRAMFS_LOAD, 'boot_drive', 'disk_error')
    a.emit(0xEA); a.imm16(STAGE2_LOAD); a.imm16(0)
    a.label('disk_error'); a.emit(0xBE); a.abs16('err_msg'); a.call('serial_print')
    a.label('hang'); a.emit(0xF4); a.jmp('hang')
    add_serial_routines(a)
    a.label('boot_msg'); a.text('Fluid HTML kernel stage1.5 loading expanded stage2\r\n')
    a.label('err_msg'); a.text('html.disk_error.stage1_5\r\n')
    a.label('boot_drive'); a.emit(0)
    data=bytearray(a.patch())
    maxlen=STAGE1_5_SECTORS*512
    if len(data) > maxlen:
        raise SystemExit(f'html stage1.5 too large {len(data)} > {maxlen}')
    print(f'html stage1.5 used {len(data)} max {maxlen} free {maxlen-len(data)} sectors={STAGE1_5_SECTORS}')
    data.extend(b'\0'*(maxlen-len(data))); return bytes(data)

def build_stage2():
    a=Asm16(STAGE2_LOAD); rel=[]; abs32=[]
    def rel32(label): rel.append((len(a.code),label)); a.emit(0,0,0,0)
    def call(label): a.emit(0xE8); rel32(label)
    def jmp(label): a.emit(0xE9); rel32(label)
    def jne(label): a.emit(0x0F,0x85); rel32(label)
    def je(label): a.emit(0x0F,0x84); rel32(label)
    def jb(label): a.emit(0x0F,0x82); rel32(label)
    def jae(label): a.emit(0x0F,0x83); rel32(label)
    def ja(label): a.emit(0x0F,0x87); rel32(label)
    def jbe(label): a.emit(0x0F,0x86); rel32(label)
    def mov_esi(label): a.emit(0xBE); abs32.append((len(a.code),label)); a.emit(0,0,0,0)
    def mov_edi(label): a.emit(0xBF); abs32.append((len(a.code),label)); a.emit(0,0,0,0)
    def print_label(label): mov_esi(label); call('serial_print32')
    def push_esi(): a.emit(0x56)
    def pop_esi(): a.emit(0x5E)
    def store32(addr,val): a.emit(0xC7,0x05); a.emit(*addr.to_bytes(4,'little')); a.emit(*val.to_bytes(4,'little'))
    def store32_label(addr,label): a.emit(0xC7,0x05); a.emit(*addr.to_bytes(4,'little')); abs32.append((len(a.code),label)); a.emit(0,0,0,0)
    def emit_mov_eax_ptr_ebx(off=0): a.emit(0x8B,0x83); a.emit(*off.to_bytes(4,'little'))
    def emit_mov_ptr_edi_eax(off=0): a.emit(0x89,0x87); a.emit(*off.to_bytes(4,'little'))
    def emit_mov_eax_ptr_esi(off=0): a.emit(0x8B,0x86); a.emit(*off.to_bytes(4,'little'))
    def emit_mov_ptr_esi_eax(off=0): a.emit(0x89,0x86); a.emit(*off.to_bytes(4,'little'))
    def emit_mov_eax_ptr_edi(off=0): a.emit(0x8B,0x87); a.emit(*off.to_bytes(4,'little'))
    def write_bytes(addr, data):
        a.emit(0xBF); a.emit(*addr.to_bytes(4,'little'))
        for b in data:
            a.emit(0xB0,b,0xAA)
    def load32(addr): a.emit(0xA1); a.emit(*addr.to_bytes(4,'little'))
    def load32_edx(addr): a.emit(0x8B,0x15); a.emit(*addr.to_bytes(4,'little'))
    def store_eax_abs(addr): a.emit(0xA3); a.emit(*addr.to_bytes(4,'little'))
    def inc32(addr): a.emit(0xFF,0x05); a.emit(*addr.to_bytes(4,'little'))
    def cmp_eax_imm(v): a.emit(0x3D); a.emit(*v.to_bytes(4,'little'))
    def cmp_edx_imm(v): a.emit(0x81,0xFA); a.emit(*v.to_bytes(4,'little'))
    def save_dom_node(tag: int, kind: int, x: int, y: int, w: int, h: int):
        # DOM record: tag, kind, label_ptr, x, y, w, h, state/style, parent, first_child, next_sibling, flags (48 bytes).
        a.emit(0x51) # push ecx
        load32(VISIBLE_DOM_COUNT)                         # eax = visible dom_count
        a.emit(0x89,0xC7)                        # edi = index
        a.emit(0x6B,0xFF,0x30)                   # *48
        a.emit(0x81,0xC7); a.emit(*VISIBLE_DOM_BASE.to_bytes(4,'little'))
        a.emit(0xC7,0x07); a.emit(*tag.to_bytes(4,'little'))
        a.emit(0xC7,0x47,0x04); a.emit(*kind.to_bytes(4,'little'))
        a.emit(0x89,0x77,0x08)                   # label_ptr = esi
        a.emit(0xC7,0x47,0x0C); a.emit(*x.to_bytes(4,'little'))
        a.emit(0xC7,0x47,0x10); a.emit(*y.to_bytes(4,'little'))
        a.emit(0xC7,0x47,0x14); a.emit(*w.to_bytes(4,'little'))
        a.emit(0xC7,0x47,0x18); a.emit(*h.to_bytes(4,'little'))
        a.emit(0xC7,0x47,0x1C); a.emit(*(0).to_bytes(4,'little'))
        load32(CURRENT_PARENT_ID)
        a.emit(0x89,0x47,0x20)                   # parent=current HTML tag stack top
        a.emit(0xC7,0x47,0x24); a.emit(*(0xFFFFFFFF).to_bytes(4,'little'))
        a.emit(0xC7,0x47,0x28); a.emit(*(0xFFFFFFFF).to_bytes(4,'little'))
        a.emit(0xC7,0x47,0x2C); a.emit(*(1).to_bytes(4,'little'))  # visible/renderable
        call('link_visible_node')
        inc32(VISIBLE_DOM_COUNT)
        a.emit(0x59) # pop ecx

    def map_text_data_from_vmap(vmap_base: int, pt32_base: int, expected_task: int, expected_text_pte: int, expected_data_pte: int, read_msg: str, map_msg: str, mmap_msg: str | None = None, deny_msg: str | None = None):
        load32(vmap_base + 0x00); cmp_eax_imm(expected_task); jne('aspace_permission_bad')
        load32(vmap_base + 0x04); cmp_eax_imm(ELF32_USER_TEXT); jne('aspace_permission_bad')
        load32(vmap_base + 0x10); cmp_eax_imm(ELF32_USER_DATA); jne('aspace_permission_bad')
        load32(vmap_base + 0x1C); cmp_eax_imm(ELF32_USER_BSS); jne('aspace_permission_bad')
        load32(vmap_base + 0x0C); cmp_eax_imm(5); jne('aspace_permission_bad')
        load32(vmap_base + 0x18); cmp_eax_imm(6); jne('aspace_permission_bad')
        load32(vmap_base + 0x24); cmp_eax_imm(6); jne('aspace_permission_bad')
        load32(vmap_base + 0x28); cmp_eax_imm(ELF32_USER_TEXT); jne('aspace_permission_bad')
        load32(vmap_base + 0x08); a.emit(0x0D); a.emit(*(0x5).to_bytes(4,'little')); store_eax_abs(pt32_base + 0x48 * 4)
        load32(vmap_base + 0x14); a.emit(0x0D); a.emit(*(0x7).to_bytes(4,'little')); store_eax_abs(pt32_base + 0x49 * 4)
        print_label(read_msg)
        load32(pt32_base + 0x48 * 4); cmp_eax_imm(expected_text_pte); jne('aspace_permission_bad')
        load32(pt32_base + 0x49 * 4); cmp_eax_imm(expected_data_pte); jne('aspace_permission_bad')
        if mmap_msg is not None:
            print_label(mmap_msg)
        if deny_msg is not None:
            load32(pt32_base + 0x48 * 4); a.emit(0xA8,0x02); jne('aspace_permission_bad')
            print_label(deny_msg)
        print_label(map_msg)

