    def rect(x,y,w,h,c):
        a.emit(0xB8); a.emit(*c.to_bytes(4,'little'))
        a.emit(0xBB); a.emit(*x.to_bytes(4,'little'))
        a.emit(0xBA); a.emit(*y.to_bytes(4,'little'))
        a.emit(0xB9); a.emit(*w.to_bytes(4,'little'))
