    def css_rule(slot, x, y, w, h, z=0):
        base = CSS_LAYOUT_RULE_BASE + slot * CSS_LAYOUT_RULE_SIZE
        store32(base + 0x00, x)
        store32(base + 0x04, y)
        store32(base + 0x08, w)
        store32(base + 0x0C, h)
        store32(CSS_Z_INDEX_BASE + slot * 4, z)
        store32(CSS_DISPLAY_BASE + slot * 4, 1)
        store32(CSS_VISIBILITY_BASE + slot * 4, 1)
    def selector_meta(slot, kind, nth=0, parent=0):
        base = CSS_SELECTOR_META_BASE + slot * CSS_SELECTOR_META_RECORD_SIZE
        store32(base + 0x00, slot)
        store32(base + 0x04, kind)
        store32(base + 0x08, nth)
        store32(base + 0x0C, parent)
