        a.emit(0x0F,0xB7,0x05); a.emit(*((image_load + 0x2E).to_bytes(4,'little'))); cmp_eax_imm(40); jne('device_registry_bad')
        a.emit(0x0F,0xB7,0x05); a.emit(*((image_load + 0x30).to_bytes(4,'little'))); cmp_eax_imm(7); jne('device_registry_bad')
        a.emit(0x0F,0xB7,0x05); a.emit(*((image_load + 0x32).to_bytes(4,'little'))); cmp_eax_imm(6); jne('device_registry_bad')
