        load32(image_load + 0x1BC + 0x21); cmp_eax_imm(0x756C662E); jne('device_registry_bad')
        load32(image_load + 0x1BC + 0x2F); cmp_eax_imm(0x7368732E); jne('device_registry_bad')
        load32(image_load + 0x34 + 1*40 + 0x00); cmp_eax_imm(1); jne('device_registry_bad')
        load32(image_load + 0x34 + 2*40 + 0x00); cmp_eax_imm(7); jne('device_registry_bad')
        load32(image_load + 0x34 + 3*40 + 0x00); cmp_eax_imm(15); jne('device_registry_bad')
        load32(image_load + 0x34 + 4*40 + 0x00); cmp_eax_imm(23); jne('device_registry_bad')
