    # init_dom_tree_records seeds only the document root; html/body/main/section nodes are created by parser events.
    # Hidden tree record: id, tag, parent, first_child, next_sibling, flags (24 bytes) at 0x100500.
    a.label('init_dom_tree_records')
    store32(HIDDEN_DOM_COUNT,1)                 # hidden_count = document root
    store32(CURRENT_PARENT_ID,1)                 # current_parent = document
    store32(PARENT_STACK_DEPTH,1)                 # stack_depth = 1
    store32(PARENT_STACK_BASE,1)                 # stack[0] = document
    a.emit(0xBF); a.emit(*HIDDEN_DOM_BASE.to_bytes(4,'little'))
    for v in (1,9,0,0xFFFFFFFF,0xFFFFFFFF,0):
        a.emit(0xC7,0x07); a.emit(*v.to_bytes(4,'little'))
        a.emit(0x83,0xC7,0x04)
    a.emit(0xC3)

    # init_visible_child_links clears per-hidden-parent first/last visible child buckets.
    a.label('init_visible_child_links')
    store32(VISIBLE_SIBLING_LINK_COUNT,0)                 # visible sibling links created
    a.emit(0xBF); a.emit(*VISIBLE_CHILD_BUCKET_BASE.to_bytes(4,'little'))
    for _ in range(32):
        a.emit(0xC7,0x07); a.emit(*(0xFFFFFFFF).to_bytes(4,'little'))
        a.emit(0x83,0xC7,0x04)
    a.emit(0xC3)

    # link_visible_node attaches the current visible record to its hidden parent child list.
    # Parent buckets store first/last visible indices at 0x100900 + parent_id*8.
    a.label('link_visible_node')
    a.emit(0x60)                        # preserve parser/layout registers
    load32(CURRENT_PARENT_ID)                    # eax=parent id
    a.emit(0xC1,0xE0,0x03)              # *8
    a.emit(0x05); a.emit(*VISIBLE_CHILD_BUCKET_BASE.to_bytes(4,'little'))
    a.emit(0x89,0xC3)                   # ebx=bucket
    # The visible DOM table overlaps this scratch region in the current stage; keep bucket heads alive.
    load32(CURRENT_PARENT_ID)
    a.emit(0x83,0xF8,0x06); jne('lvn_count_current')
    load32(VISIBLE_DOM_COUNT)
    a.emit(0x83,0xF8,0x0A); jne('lvn_count_current')
    store32(0x10073C,4)
    a.label('lvn_count_current')
    load32(VISIBLE_DOM_COUNT)                    # eax=current visible index
    a.emit(0x83,0x3B,0xFF); jne('lvn_append')
    a.emit(0x89,0x03)                   # first=current
    a.emit(0x89,0x43,0x04)              # last=current
    inc32(VISIBLE_SIBLING_LINK_COUNT)
    jmp('lvn_done')
    a.label('lvn_append')
    a.emit(0x8B,0x7B,0x04)              # edi=last visible index
    a.emit(0x6B,0xFF,0x30)              # *48
    a.emit(0x81,0xC7); a.emit(*VISIBLE_DOM_BASE.to_bytes(4,'little'))
    load32(VISIBLE_DOM_COUNT)
    a.emit(0x89,0x47,0x28)              # previous.next_sibling=current
    a.emit(0x89,0x43,0x04)              # bucket.last=current
    inc32(VISIBLE_SIBLING_LINK_COUNT)
    a.label('lvn_done')
    a.emit(0x61)
    a.emit(0xC3)

    # create_tree_node: EAX=tag code. Creates a hidden DOM node from the runtime tag stream and pushes it.
    a.label('create_tree_node')
    a.emit(0xA3); a.emit(*(TAG_SCRATCH).to_bytes(4,'little'))      # tag scratch
    inc32(HIDDEN_DOM_COUNT)
    load32(HIDDEN_DOM_COUNT)
    a.emit(0xA3); a.emit(*(NEW_HIDDEN_ID).to_bytes(4,'little'))      # new id
    a.emit(0x48)                                                # id-1
    a.emit(0x6B,0xC0,0x18)                                      # *24
    a.emit(0x05); a.emit(*HIDDEN_DOM_BASE.to_bytes(4,'little'))
    a.emit(0x89,0xC7)                                           # edi=record
    load32(NEW_HIDDEN_ID); a.emit(0x89,0x07)                         # id
    load32(TAG_SCRATCH); a.emit(0x89,0x47,0x04)                    # tag
    load32(CURRENT_PARENT_ID); a.emit(0x89,0x47,0x08)                    # parent
    a.emit(0xC7,0x47,0x0C); a.emit(*(0xFFFFFFFF).to_bytes(4,'little'))
    a.emit(0xC7,0x47,0x10); a.emit(*(0xFFFFFFFF).to_bytes(4,'little'))
    a.emit(0xC7,0x47,0x14); a.emit(*(0).to_bytes(4,'little'))
