    a.emit(0x48)
    a.emit(0x6B,0xC0,0x18)
    a.emit(0x05); a.emit(*HIDDEN_DOM_BASE.to_bytes(4,'little'))
    a.emit(0x89,0xC3)                                           # ebx=parent record
    a.emit(0x83,0x7B,0x0C,0xFF); jne('ctn_append_hidden')
    load32(NEW_HIDDEN_ID); a.emit(0x89,0x43,0x0C); a.emit(0x89,0x43,0x14)
    jmp('ctn_hidden_linked')
    a.label('ctn_append_hidden')
    a.emit(0x8B,0x7B,0x14)                                      # edi=parent.last_child id
    a.emit(0x4F)
    a.emit(0x6B,0xFF,0x18)
    a.emit(0x81,0xC7); a.emit(*HIDDEN_DOM_BASE.to_bytes(4,'little'))
    load32(NEW_HIDDEN_ID); a.emit(0x89,0x47,0x10); a.emit(0x89,0x43,0x14)
    a.label('ctn_hidden_linked')
    # Push hidden node id to parser parent stack.
    load32(PARENT_STACK_DEPTH)
    a.emit(0x89,0xC7)
    a.emit(0xC1,0xE7,0x02)
    a.emit(0x81,0xC7); a.emit(*PARENT_STACK_BASE.to_bytes(4,'little'))
    load32(NEW_HIDDEN_ID); a.emit(0x89,0x07)
    inc32(PARENT_STACK_DEPTH)
    load32(NEW_HIDDEN_ID); a.emit(0xA3); a.emit(*(CURRENT_PARENT_ID).to_bytes(4,'little'))
    a.emit(0xC3)

    # pop_tree_node handles </html>, </body>, </main>, and </section> from the runtime parser.
    a.label('pop_tree_node')
    inc32(CLOSE_COUNT)
    load32(PARENT_STACK_DEPTH)
    a.emit(0x83,0xE8,0x01)
    a.emit(0xA3); a.emit(*(PARENT_STACK_DEPTH).to_bytes(4,'little'))
    a.emit(0x83,0xE8,0x01)
    a.emit(0x89,0xC7)
    a.emit(0xC1,0xE7,0x02)
    a.emit(0x81,0xC7); a.emit(*PARENT_STACK_BASE.to_bytes(4,'little'))
    a.emit(0x8B,0x07)
    a.emit(0xA3); a.emit(*(CURRENT_PARENT_ID).to_bytes(4,'little'))
    a.emit(0xC3)

    # parse_css_style scans <style>.class{background:color}</style> into css class table.
    a.label('parse_css_style')
    a.emit(0x56)                       # preserve style cursor for later CSS layout parser
    a.label('pcs_loop')
    a.emit(0x8A,0x06)
    a.emit(0x84,0xC0); je('pcs_done')
    a.emit(0x3C,ord('.')); jne('pcs_next')
