    a.emit(0x80,0x7E,0x0B,ord('"')); je('pbc_gold')
    jmp('pbc_next')
    a.label('pbc_base'); store32(CLASS_ID_SCRATCH,1); load32(CSS_BASE_COLOR); a.emit(0xA3); a.emit(*(CURRENT_BUTTON_STYLE).to_bytes(4,'little')); jmp('pbc_done')
    a.label('pbc_info'); store32(CLASS_ID_SCRATCH,2); load32(CSS_INFO_COLOR); a.emit(0xA3); a.emit(*(CURRENT_BUTTON_STYLE).to_bytes(4,'little')); jmp('pbc_done')
    a.label('pbc_danger'); store32(CLASS_ID_SCRATCH,3); load32(CSS_DANGER_COLOR); a.emit(0xA3); a.emit(*(CURRENT_BUTTON_STYLE).to_bytes(4,'little')); jmp('pbc_done')
    a.label('pbc_warm'); store32(CLASS_ID_SCRATCH,4); load32(CSS_WARM_COLOR); a.emit(0xA3); a.emit(*(CURRENT_BUTTON_STYLE).to_bytes(4,'little')); jmp('pbc_done')
    a.label('pbc_gold'); store32(CLASS_ID_SCRATCH,5); load32(CSS_GOLD_COLOR); a.emit(0xA3); a.emit(*(CURRENT_BUTTON_STYLE).to_bytes(4,'little')); jmp('pbc_done')
    a.label('pbc_next')
    a.emit(0x46)
    jmp('pbc_loop')
    a.label('pbc_done')
    a.emit(0x5E)
    a.emit(0xC3)


    # save_h2_dom_node stores the real <h2> innerText pointer from the runtime HTML source.
    a.label('save_h2_dom_node')
    a.emit(0x51)                       # push ecx
    load32(VISIBLE_DOM_COUNT)
    a.emit(0x89,0xC7)
    a.emit(0x6B,0xFF,0x30)
    a.emit(0x81,0xC7); a.emit(*VISIBLE_DOM_BASE.to_bytes(4,'little'))
    a.emit(0xC7,0x07); a.emit(*(2).to_bytes(4,'little'))
    a.emit(0xC7,0x47,0x04); a.emit(*(1).to_bytes(4,'little'))
    a.emit(0x89,0x77,0x08)             # label_ptr = runtime innerText
    a.emit(0xC7,0x47,0x0C); a.emit(*(0).to_bytes(4,'little'))
    a.emit(0xC7,0x47,0x10); a.emit(*(0).to_bytes(4,'little'))
    a.emit(0xC7,0x47,0x14); a.emit(*(0).to_bytes(4,'little'))
    a.emit(0xC7,0x47,0x18); a.emit(*(0).to_bytes(4,'little'))
    a.emit(0xC7,0x47,0x1C); a.emit(*(0).to_bytes(4,'little'))
    load32(CURRENT_PARENT_ID); a.emit(0x89,0x47,0x20)
    a.emit(0xC7,0x47,0x24); a.emit(*(0xFFFFFFFF).to_bytes(4,'little'))
    a.emit(0xC7,0x47,0x28); a.emit(*(0xFFFFFFFF).to_bytes(4,'little'))
    a.emit(0xC7,0x47,0x2C); a.emit(*(1).to_bytes(4,'little'))
    call('link_visible_node')
    inc32(VISIBLE_DOM_COUNT)
    a.emit(0x59)
    a.emit(0xC3)

    # save_button_dom_node stores runtime innerText only; rects are computed later by compute_layout_pass.
    a.label('save_button_dom_node')
    a.emit(0x56)                       # preserve label ptr
    a.emit(0x31,0xDB)                  # x=0
    a.emit(0x31,0xD2)                  # y=0
    a.emit(0x31,0xC9)                  # w=0
    store32(SCRATCH_HEIGHT,0)                # h=0
    a.emit(0x5E)                       # restore label ptr to esi
    call('save_dom_node_runtime_rect')
    inc32(BUTTON_SAVE_COUNT)
    a.emit(0xC3)

    # save_dom_node_runtime_rect: tag=button kind=button, label_ptr=ESI, rect EBX/EDX/ECX/[100034].
    a.label('save_dom_node_runtime_rect')
    a.emit(0x56)                       # preserve label ptr for caller logging
    a.emit(0x51)                       # push ecx width
    load32(VISIBLE_DOM_COUNT)
    a.emit(0x89,0xC7)
    a.emit(0x6B,0xFF,0x30)
    a.emit(0x81,0xC7); a.emit(*VISIBLE_DOM_BASE.to_bytes(4,'little'))
    a.emit(0xC7,0x07); a.emit(*(1).to_bytes(4,'little'))
    a.emit(0xC7,0x47,0x04); a.emit(*(2).to_bytes(4,'little'))
    a.emit(0x89,0x77,0x08)
    a.emit(0x89,0x5F,0x0C)
    a.emit(0x89,0x57,0x10)
    a.emit(0x59)                       # pop width into ecx
    a.emit(0x89,0x4F,0x14)
    load32(SCRATCH_HEIGHT)
    a.emit(0x89,0x47,0x18)
    load32(CURRENT_BUTTON_STYLE)
    a.emit(0x89,0x47,0x1C)
    load32(CURRENT_PARENT_ID)
    a.emit(0x89,0x47,0x20)
    a.emit(0xC7,0x47,0x24); a.emit(*(0xFFFFFFFF).to_bytes(4,'little'))
    a.emit(0xC7,0x47,0x28); a.emit(*(0xFFFFFFFF).to_bytes(4,'little'))
    a.emit(0xC7,0x47,0x2C); a.emit(*(1).to_bytes(4,'little'))
    call('link_visible_node')
    inc32(VISIBLE_DOM_COUNT)
    a.emit(0x5E)
    a.emit(0xC3)

    # compute_layout_pass is a separate kernel pipeline pass after parse/style and before paint/input.
    a.label('compute_layout_pass')
    store32(MAIN_FLOW_COL,0)                # main flow index
    store32(SECTION_FLOW_INDEX,0)                # section flow index
    store32(MAIN_FLOW_X,18)               # main flow cursor x
    store32(MAIN_FLOW_Y,104)               # main flow cursor y
    store32(SECTION_FLOW_X,36)               # CSS .card button cursor x
    store32(SECTION_FLOW_Y,80)               # CSS .card button cursor y
    store32(LAYOUT_VISIBLE_COUNT,0)                # layout-computed visible node count
    store32(SVG_FLOW_INDEX,0)                # svg layout flow index
    load32(MAIN_NODE_ID)
    call('layout_hidden_children')
    load32(MAIN_NODE_ID); a.emit(0xA3); a.emit(*(CURRENT_PARENT_BUCKET_ID).to_bytes(4,'little'))
    call('layout_child_bucket')
    a.emit(0xC3)

    a.label('layout_hidden_children')
    a.emit(0x48)
    a.emit(0x6B,0xC0,0x18)
    a.emit(0x05); a.emit(*HIDDEN_DOM_BASE.to_bytes(4,'little'))
    a.emit(0x8B,0x40,0x0C)
    a.emit(0xA3); a.emit(*(HIDDEN_TRAVERSAL_ID).to_bytes(4,'little'))
    a.label('lhc_loop')
    load32(HIDDEN_TRAVERSAL_ID)
    a.emit(0x83,0xF8,0xFF)
    je('lhc_done')
    a.emit(0xA3); a.emit(*(CURRENT_PARENT_BUCKET_ID).to_bytes(4,'little'))
    call('layout_child_bucket')
    load32(HIDDEN_TRAVERSAL_ID)
    a.emit(0x48)
    a.emit(0x6B,0xC0,0x18)
    a.emit(0x05); a.emit(*HIDDEN_DOM_BASE.to_bytes(4,'little'))
    a.emit(0x8B,0x40,0x10)
    a.emit(0xA3); a.emit(*(HIDDEN_TRAVERSAL_ID).to_bytes(4,'little'))
    jmp('lhc_loop')
    a.label('lhc_done')
    a.emit(0xC3)

    a.label('layout_child_bucket')
    load32(CURRENT_PARENT_BUCKET_ID)
    a.emit(0xC1,0xE0,0x03)
    a.emit(0x05); a.emit(*VISIBLE_CHILD_BUCKET_BASE.to_bytes(4,'little'))
    a.emit(0x8B,0x00)
    a.emit(0xA3); a.emit(*(ITER_INDEX).to_bytes(4,'little'))
    a.label('lcb_loop')
    load32(ITER_INDEX)
    a.emit(0x83,0xF8,0xFF)
    je('lcb_done')
    a.emit(0x89,0xC7); a.emit(0x6B,0xFF,0x30); a.emit(0x81,0xC7); a.emit(*VISIBLE_DOM_BASE.to_bytes(4,'little'))
    a.emit(0xC7,0x47,0x2C); a.emit(*(3).to_bytes(4,'little'))  # visible + layout-computed
    inc32(LAYOUT_VISIBLE_COUNT)
    a.emit(0x8B,0x07)
    a.emit(0x83,0xF8,0x01); je('layout_button_node')
    a.emit(0x83,0xF8,0x02); je('layout_h2_node')
    a.emit(0x83,0xF8,0x03); je('layout_input_node')
    a.emit(0x83,0xF8,0x04); je('layout_svg_node')
    jmp('lcb_next')
    a.label('layout_h2_node')
    load32(CURRENT_PARENT_BUCKET_ID)
    a.emit(0x3B,0x05); a.emit(*(FIRST_SECTION_ID).to_bytes(4,'little'))
    jne('layout_h2_second_section_node')
    a.emit(0xB8); a.emit(*(CSS_H2_FIRST_SLOT).to_bytes(4,'little'))
    call('layout_apply_css_rule_by_eax')
    jmp('layout_h2_size')
    a.label('layout_h2_second_section_node')
    a.emit(0xB8); a.emit(*(CSS_H2_SECOND_SLOT).to_bytes(4,'little'))
    call('layout_apply_css_rule_by_eax')
    a.label('layout_h2_size')
    a.emit(0xC7,0x47,0x14); a.emit(*(40).to_bytes(4,'little'))
    a.emit(0xC7,0x47,0x18); a.emit(*(6).to_bytes(4,'little'))
    jmp('lcb_next')
    a.label('layout_input_node')
    load_css_rule(0)
    a.emit(0x89,0x5F,0x0C); a.emit(0x89,0x57,0x10); a.emit(0x89,0x4F,0x14); a.emit(0x89,0x77,0x18)
    jmp('lcb_next')
    a.label('layout_svg_node')
    load32(SVG_FLOW_INDEX)                   # svg flow index -> css rule slot 1..3
    a.emit(0x83,0xC0,0x01)
    call('layout_apply_css_rule_by_eax')
    # General svg{width/height} rules are inherited from the CSS subset fallback.
    a.emit(0xC7,0x47,0x14); a.emit(*(14).to_bytes(4,'little'))
    a.emit(0xC7,0x47,0x18); a.emit(*(14).to_bytes(4,'little'))
    inc32(SVG_FLOW_INDEX)
    jmp('lcb_next')
    a.label('layout_button_node')
    load32(CURRENT_PARENT_BUCKET_ID)
    a.emit(0x3B,0x05); a.emit(*(MAIN_NODE_ID).to_bytes(4,'little'))
    je('layout_main_node')
    load32(SECTION_FLOW_INDEX)                 # first card buttons use css slots 4..7
    a.emit(0x83,0xF8,0x04); jae('layout_section_button_hide')
    a.emit(0x83,0xC0,0x04)
    call('layout_apply_css_rule_by_eax')
    # Section button selectors provide position; the generic button rule supplies size.
    a.emit(0xC7,0x47,0x14); a.emit(*(66).to_bytes(4,'little'))
    a.emit(0xC7,0x47,0x18); a.emit(*(18).to_bytes(4,'little'))
    inc32(SECTION_FLOW_INDEX)
    jmp('lcb_next')
    a.label('layout_section_button_hide')
    a.emit(0xC7,0x47,0x0C); a.emit(*(320).to_bytes(4,'little'))
    a.emit(0xC7,0x47,0x10); a.emit(*(200).to_bytes(4,'little'))
    a.emit(0xC7,0x47,0x14); a.emit(*(0).to_bytes(4,'little'))
    a.emit(0xC7,0x47,0x18); a.emit(*(0).to_bytes(4,'little'))
    inc32(SECTION_FLOW_INDEX)
    jmp('lcb_next')
    a.label('layout_main_node')
    load32(MAIN_FLOW_COL)                      # main buttons use css slots 8..18
    a.emit(0x83,0xC0,0x08)
    call('layout_apply_css_rule_by_eax')
    load32(CSS_RULE_DIRTY); a.emit(0x85,0xC0); jne('layout_main_rule_dirty')
    a.emit(0xC7,0x47,0x14); a.emit(*(66).to_bytes(4,'little'))
    a.emit(0xC7,0x47,0x18); a.emit(*(18).to_bytes(4,'little'))
    jmp('layout_main_rule_done')
    a.label('layout_main_rule_dirty')
    load32(CSS_BUTTON_DEFAULT_WIDTH); cmp_eax_imm(16); jb('layout_main_fallback_width'); a.emit(0x89,0x47,0x14); jmp('layout_main_width_done')
    a.label('layout_main_fallback_width')
    a.emit(0xC7,0x47,0x14); a.emit(*(66).to_bytes(4,'little'))
    a.label('layout_main_width_done')
    load32(CSS_BUTTON_DEFAULT_HEIGHT); cmp_eax_imm(8); jb('layout_main_fallback_height'); a.emit(0x89,0x47,0x18); jmp('layout_main_height_done')
    a.label('layout_main_fallback_height')
    a.emit(0xC7,0x47,0x18); a.emit(*(18).to_bytes(4,'little'))
    a.label('layout_main_height_done')
    a.label('layout_main_rule_done')
    inc32(MAIN_FLOW_COL)
    a.label('layout_main_no_wrap')
    a.label('lcb_next')
    a.emit(0x8B,0x47,0x28); a.emit(0xA3); a.emit(*(ITER_INDEX).to_bytes(4,'little'))
    jmp('lcb_loop')
    a.label('lcb_done')
    a.emit(0xC3)

    a.label('layout_apply_css_rule_by_eax')
    a.emit(0xC1,0xE0,0x04)              # slot * 16
    a.emit(0x05); a.emit(*CSS_LAYOUT_RULE_BASE.to_bytes(4,'little'))
    a.emit(0x8B,0x18); a.emit(0x89,0x5F,0x0C)
    a.emit(0x8B,0x50,0x04); a.emit(0x89,0x57,0x10)
    a.emit(0x8B,0x48,0x08); a.emit(0x89,0x4F,0x14)
    a.emit(0x8B,0x70,0x0C); a.emit(0x89,0x77,0x18)
    a.emit(0xC3)

    a.label('damage_queue_push_current_rect')
    # Push one mutation damage record: {x,y,w,h,node,source}. Overflow keeps union state and records a drop.
    load32(DAMAGE_QUEUE_COUNT)
    cmp_eax_imm(DAMAGE_QUEUE_CAP)
    jae('damage_queue_full')
    load32(DAMAGE_QUEUE_TAIL)
    a.emit(0x89,0xC7)
    a.emit(0x6B,0xFF,DAMAGE_QUEUE_RECORD_SIZE)
    a.emit(0x81,0xC7); a.emit(*DAMAGE_QUEUE_BASE.to_bytes(4,'little'))
    a.emit(0x89,0x1F)                  # x
    a.emit(0x89,0x57,0x04)             # y
    a.emit(0x89,0x4F,0x08)             # w
    a.emit(0x89,0x77,0x0C)             # h
    load32(INVALIDATE_NODE); a.emit(0x89,0x47,0x10)
    load32(INVALIDATE_SOURCE); a.emit(0x89,0x47,0x14)
    load32(DAMAGE_QUEUE_TAIL)
    a.emit(0x40)
    cmp_eax_imm(DAMAGE_QUEUE_CAP)
    jne('damage_queue_tail_ok')
    a.emit(0x31,0xC0)
    a.label('damage_queue_tail_ok')
    store_eax_abs(DAMAGE_QUEUE_TAIL)
    inc32(DAMAGE_QUEUE_COUNT)
    a.emit(0xC3)
    a.label('damage_queue_full')
    inc32(DAMAGE_QUEUE_DROPS)
    print_label('compositor_damage_queue_full_msg')
    a.emit(0xC3)

    a.label('compositor_invalidate_rect')
    # Args: EBX=x, EDX=y, ECX=w, ESI=h, EAX=node/index-or-source. Stores damage queue + union.
    a.emit(0x60)
    a.emit(0xA3); a.emit(*(INVALIDATE_NODE).to_bytes(4,'little'))
    load32(INVALIDATE_STATE)
    a.emit(0x85,0xC0); jne('invalidate_merge')
    a.emit(0x89,0x1D); a.emit(*(INVALIDATE_X1).to_bytes(4,'little'))
    a.emit(0x89,0x15); a.emit(*(INVALIDATE_Y1).to_bytes(4,'little'))
    a.emit(0x89,0xD8); a.emit(0x01,0xC8); store_eax_abs(INVALIDATE_X2)
    a.emit(0x89,0xD0); a.emit(0x01,0xF0); store_eax_abs(INVALIDATE_Y2)
    store32(INVALIDATE_STATE,1)
    inc32(INVALIDATE_COUNT)
    call('damage_queue_push_current_rect')
    jmp('invalidate_done')
    a.label('invalidate_merge')
    a.emit(0x89,0xD8); a.emit(0x3B,0x05); a.emit(*(INVALIDATE_X1).to_bytes(4,'little')); jae('invalidate_x1_ok'); store_eax_abs(INVALIDATE_X1)
    a.label('invalidate_x1_ok')
    a.emit(0x89,0xD0); a.emit(0x3B,0x05); a.emit(*(INVALIDATE_Y1).to_bytes(4,'little')); jae('invalidate_y1_ok'); store_eax_abs(INVALIDATE_Y1)
    a.label('invalidate_y1_ok')
    a.emit(0x89,0xD8); a.emit(0x01,0xC8); a.emit(0x3B,0x05); a.emit(*(INVALIDATE_X2).to_bytes(4,'little')); jbe('invalidate_x2_ok'); store_eax_abs(INVALIDATE_X2)
    a.label('invalidate_x2_ok')
    a.emit(0x89,0xD0); a.emit(0x01,0xF0); a.emit(0x3B,0x05); a.emit(*(INVALIDATE_Y2).to_bytes(4,'little')); jbe('invalidate_y2_ok'); store_eax_abs(INVALIDATE_Y2)
    a.label('invalidate_y2_ok')
    inc32(INVALIDATE_COUNT)
    call('damage_queue_push_current_rect')
    a.label('invalidate_done')
    a.emit(0x61)
    a.emit(0xC3)

    a.label('compositor_invalidate_node_current')
    a.emit(0x8B,0x3D); a.emit(*(CURRENT_NODE_PTR).to_bytes(4,'little'))
    a.emit(0x8B,0x5F,0x0C)
    a.emit(0x8B,0x57,0x10)
    a.emit(0x8B,0x4F,0x14)
    a.emit(0x8B,0x77,0x18)
    store32(INVALIDATE_SOURCE,2)
    a.emit(0x8B,0x05); a.emit(*(VISIBLE_DOM_ALLOC_RESULT).to_bytes(4,'little'))
    call('compositor_invalidate_rect')
    a.emit(0xC3)

    a.label('compositor_invalidate_input_range')
    a.emit(0xBB); a.emit(*(170).to_bytes(4,'little'))
    a.emit(0xBA); a.emit(*(40).to_bytes(4,'little'))
    a.emit(0xB9); a.emit(*(120).to_bytes(4,'little'))
    a.emit(0xBE); a.emit(*(28).to_bytes(4,'little'))
    store32(INVALIDATE_SOURCE,1)
    a.emit(0xB8); a.emit(*(3).to_bytes(4,'little'))
    call('compositor_invalidate_rect')
    a.emit(0xC3)

    a.label('compositor_seed_dirty_from_invalidation')
    load32(DAMAGE_QUEUE_COUNT)
    a.emit(0x85,0xC0); je('csdfi_fallback_union')
    store32(DAMAGE_QUEUE_UNION_COUNT,0)
    a.label('csdfi_queue_loop')
    load32(DAMAGE_QUEUE_COUNT)
    a.emit(0x85,0xC0); je('csdfi_queue_done')
    load32(DAMAGE_QUEUE_HEAD)
    a.emit(0x89,0xC7)
    a.emit(0x6B,0xFF,DAMAGE_QUEUE_RECORD_SIZE)
    a.emit(0x81,0xC7); a.emit(*DAMAGE_QUEUE_BASE.to_bytes(4,'little'))
    a.emit(0x89,0x3D); a.emit(*(DAMAGE_QUEUE_RECORD).to_bytes(4,'little'))
    load32(DAMAGE_QUEUE_UNION_COUNT)
    a.emit(0x85,0xC0); jne('csdfi_merge_record')
    a.emit(0x8B,0x07); store_eax_abs(DIRTY_RECT_X1)
    a.emit(0x8B,0x47,0x04); store_eax_abs(DIRTY_RECT_Y1)
    a.emit(0x8B,0x07); a.emit(0x03,0x47,0x08); store_eax_abs(DIRTY_RECT_X2)
    a.emit(0x8B,0x47,0x04); a.emit(0x03,0x47,0x0C); store_eax_abs(DIRTY_RECT_Y2)
    store32(DIRTY_RECT_STATE,1)
    inc32(DAMAGE_QUEUE_UNION_COUNT)
    jmp('csdfi_pop_record')
    a.label('csdfi_merge_record')
    a.emit(0x8B,0x07); a.emit(0x3B,0x05); a.emit(*(DIRTY_RECT_X1).to_bytes(4,'little')); jae('csdfi_x1_ok'); store_eax_abs(DIRTY_RECT_X1)
    a.label('csdfi_x1_ok')
    a.emit(0x8B,0x47,0x04); a.emit(0x3B,0x05); a.emit(*(DIRTY_RECT_Y1).to_bytes(4,'little')); jae('csdfi_y1_ok'); store_eax_abs(DIRTY_RECT_Y1)
    a.label('csdfi_y1_ok')
    a.emit(0x8B,0x07); a.emit(0x03,0x47,0x08); a.emit(0x3B,0x05); a.emit(*(DIRTY_RECT_X2).to_bytes(4,'little')); jbe('csdfi_x2_ok'); store_eax_abs(DIRTY_RECT_X2)
    a.label('csdfi_x2_ok')
    a.emit(0x8B,0x47,0x04); a.emit(0x03,0x47,0x0C); a.emit(0x3B,0x05); a.emit(*(DIRTY_RECT_Y2).to_bytes(4,'little')); jbe('csdfi_y2_ok'); store_eax_abs(DIRTY_RECT_Y2)
    a.label('csdfi_y2_ok')
    inc32(DAMAGE_QUEUE_UNION_COUNT)
    a.label('csdfi_pop_record')
    load32(DAMAGE_QUEUE_HEAD)
    a.emit(0x40)
    cmp_eax_imm(DAMAGE_QUEUE_CAP)
    jne('csdfi_head_ok')
    a.emit(0x31,0xC0)
    a.label('csdfi_head_ok')
    store_eax_abs(DAMAGE_QUEUE_HEAD)
    load32(DAMAGE_QUEUE_COUNT); a.emit(0x83,0xE8,0x01); store_eax_abs(DAMAGE_QUEUE_COUNT)
    jmp('csdfi_queue_loop')
    a.label('csdfi_queue_done')
    load32(DAMAGE_QUEUE_UNION_COUNT); store_eax_abs(DIRTY_RECT_COUNT)
    print_label('compositor_damage_queue_consume_msg')
    a.emit(0xC3)
    a.label('csdfi_fallback_union')
    load32(INVALIDATE_STATE)
    a.emit(0x85,0xC0); je('csdfi_done')
    load32(INVALIDATE_X1); store_eax_abs(DIRTY_RECT_X1)
    load32(INVALIDATE_Y1); store_eax_abs(DIRTY_RECT_Y1)
    load32(INVALIDATE_X2); store_eax_abs(DIRTY_RECT_X2)
    load32(INVALIDATE_Y2); store_eax_abs(DIRTY_RECT_Y2)
    store32(DIRTY_RECT_STATE,1)
    load32(INVALIDATE_COUNT); store_eax_abs(DIRTY_RECT_COUNT); store_eax_abs(DAMAGE_QUEUE_UNION_COUNT)
    a.label('csdfi_done')
    a.emit(0xC3)

    a.label('build_css_selector_match_table')
    # Selector engine materializes dom_index -> css_slot matches before computed-style.
    store32(CSS_SELECTOR_MATCH_COUNT,0)
