    a.emit(0x8B,0x03)
    a.emit(0x3B,0x05); a.emit(*(RENDER_TREE_SCAN).to_bytes(4,'little'))
    je('csl_found')
    inc32(COMPUTED_STYLE_SCAN)
    jmp('csl_loop')
    a.label('csl_found')
    a.emit(0x89,0x1D); a.emit(*(COMPUTED_STYLE_PTR).to_bytes(4,'little'))
    a.label('csl_done')
    a.emit(0xC3)

    a.label('build_render_tree_from_dom')
    # Build a separate render-node table from visible DOM records: dom_index, dom_ptr, render_op, x/y/w/h, style, z_order, flags.
    call('compute_dom_computed_styles')
    store32(RENDER_TREE_COUNT,0)
    store32(RENDER_TREE_SCAN,0)
    a.label('brt_loop')
    load32(RENDER_TREE_SCAN)
    a.emit(0x3D); a.emit(*(VISIBLE_DOM_CAP).to_bytes(4,'little'))
    jae('brt_done')
    a.emit(0x89,0xC6)                  # esi = dom index
    a.emit(0x89,0xC7)
    a.emit(0x6B,0xFF,VISIBLE_DOM_RECORD_SIZE)
    a.emit(0x81,0xC7); a.emit(*VISIBLE_DOM_BASE.to_bytes(4,'little'))
    a.emit(0x8B,0x07)
    a.emit(0x85,0xC0); je('brt_next')
    a.emit(0x8B,0x07)
    a.emit(0x83,0xF8,0x01); je('brt_maybe_emit_render_node')
    a.emit(0x83,0xF8,0x02); je('brt_maybe_emit_render_node')
    a.emit(0x83,0xF8,0x03); je('brt_maybe_emit_render_node')
    a.emit(0x83,0xF8,0x04); je('brt_maybe_emit_render_node')
    a.emit(0x83,0xF8,0x05); je('brt_maybe_emit_render_node')
    jmp('brt_next')
    a.label('brt_maybe_emit_render_node')
    # Render tree consumes computed style; DOM remains payload.
    call('computed_style_lookup_current_dom')
    load32(COMPUTED_STYLE_PTR)
    a.emit(0x85,0xC0); je('brt_emit_render_node')
    a.emit(0x89,0xC3)
    a.emit(0x8B,0x43,0x04)             # computed display flag
    a.emit(0x85,0xC0); je('brt_visibility_skip')
    a.emit(0x8B,0x43,0x08)             # computed visibility flag
    a.emit(0x85,0xC0); je('brt_visibility_skip')
    jmp('brt_emit_render_node')
    a.label('brt_visibility_skip')
    print_label('render_tree_visibility_cull_msg')
    jmp('brt_next')
    a.label('brt_emit_render_node')
    load32(RENDER_TREE_COUNT)
    a.emit(0x3D); a.emit(*(RENDER_NODE_CAP).to_bytes(4,'little'))
    jae('brt_done')
    a.emit(0x89,0xC3)
    a.emit(0x6B,0xDB,RENDER_NODE_RECORD_SIZE)
    a.emit(0x81,0xC3); a.emit(*RENDER_TREE_BASE.to_bytes(4,'little'))
    a.emit(0x89,0x33)                  # render.dom_index
    a.emit(0x89,0x7B,0x04)             # render.dom_ptr
    a.emit(0x8B,0x07); a.emit(0x89,0x43,0x08)  # render_op currently derived from DOM tag; DOM is payload only for painters
    a.emit(0x8B,0x47,0x0C); a.emit(0x89,0x43,0x0C)
    a.emit(0x8B,0x47,0x10); a.emit(0x89,0x43,0x10)
    a.emit(0x8B,0x47,0x14); a.emit(0x89,0x43,0x14)
    a.emit(0x8B,0x47,0x18); a.emit(0x89,0x43,0x18)
    a.emit(0x8B,0x47,0x1C); a.emit(0x89,0x43,0x1C)
    load32(RENDER_TREE_COUNT); a.emit(0x89,0x43,0x20)  # fallback z_order before computed style is consumed
    load32(COMPUTED_STYLE_PTR)
    a.emit(0x85,0xC0); je('brt_z_order_done')
    a.emit(0x89,0xC6)
    a.emit(0x8B,0x46,0x0C); a.emit(0x89,0x43,0x20)  # z_order from computed style, not DOM/build order
    a.label('brt_z_order_done')
    a.emit(0x8B,0x47,0x2C); a.emit(0x89,0x43,0x24)  # render flags/visibility + occlusion bits snapshot
    inc32(RENDER_TREE_COUNT)
    a.label('brt_next')
    inc32(RENDER_TREE_SCAN)
    jmp('brt_loop')
    a.label('brt_done')
    inc32(RENDER_TREE_BUILD_COUNT)
    print_label('render_tree_build_msg')
    print_label('css_z_index_parse_msg')
    print_label('css_visibility_parse_msg')
    print_label('computed_z_order_msg')
    call('sort_render_tree_by_z_order')
    a.emit(0xC3)

    a.label('sort_render_tree_by_z_order')
    # In-place stable bubble sort by render-node z_order. Equal z keeps DOM/layout order.
    store32(RENDER_TREE_SWAP_COUNT,0)
    store32(RENDER_TREE_SORT_I,0)
    a.label('srz_outer')
    load32(RENDER_TREE_SORT_I)
    a.emit(0x3B,0x05); a.emit(*(RENDER_TREE_COUNT).to_bytes(4,'little'))
    jae('srz_done')
    store32(RENDER_TREE_SORT_J,0)
    a.label('srz_inner')
    load32(RENDER_TREE_COUNT)
    a.emit(0x83,0xF8,0x01); jbe('srz_next_outer')
    a.emit(0x83,0xE8,0x01)
    a.emit(0x3B,0x05); a.emit(*(RENDER_TREE_SORT_J).to_bytes(4,'little'))
    jbe('srz_next_outer')
    load32(RENDER_TREE_SORT_J)
    a.emit(0x89,0xC7)
    a.emit(0x6B,0xFF,RENDER_NODE_RECORD_SIZE)
    a.emit(0x81,0xC7); a.emit(*RENDER_TREE_BASE.to_bytes(4,'little'))
    a.emit(0x89,0xFE); a.emit(0x83,0xC6,RENDER_NODE_RECORD_SIZE)
    a.emit(0x8B,0x47,0x20)
    a.emit(0x3B,0x46,0x20)
    jbe('srz_no_swap')
    a.emit(0x8B,0x07); a.emit(0x8B,0x16); a.emit(0x89,0x17); a.emit(0x89,0x06)
    a.emit(0x8B,0x47,0x04); a.emit(0x8B,0x56,0x04); a.emit(0x89,0x57,0x04); a.emit(0x89,0x46,0x04)
    a.emit(0x8B,0x47,0x08); a.emit(0x8B,0x56,0x08); a.emit(0x89,0x57,0x08); a.emit(0x89,0x46,0x08)
    a.emit(0x8B,0x47,0x0C); a.emit(0x8B,0x56,0x0C); a.emit(0x89,0x57,0x0C); a.emit(0x89,0x46,0x0C)
    a.emit(0x8B,0x47,0x10); a.emit(0x8B,0x56,0x10); a.emit(0x89,0x57,0x10); a.emit(0x89,0x46,0x10)
    a.emit(0x8B,0x47,0x14); a.emit(0x8B,0x56,0x14); a.emit(0x89,0x57,0x14); a.emit(0x89,0x46,0x14)
    a.emit(0x8B,0x47,0x18); a.emit(0x8B,0x56,0x18); a.emit(0x89,0x57,0x18); a.emit(0x89,0x46,0x18)
    a.emit(0x8B,0x47,0x1C); a.emit(0x8B,0x56,0x1C); a.emit(0x89,0x57,0x1C); a.emit(0x89,0x46,0x1C)
    a.emit(0x8B,0x47,0x20); a.emit(0x8B,0x56,0x20); a.emit(0x89,0x57,0x20); a.emit(0x89,0x46,0x20)
    a.emit(0x8B,0x47,0x24); a.emit(0x8B,0x56,0x24); a.emit(0x89,0x57,0x24); a.emit(0x89,0x46,0x24)
    inc32(RENDER_TREE_SWAP_COUNT)
    a.label('srz_no_swap')
    inc32(RENDER_TREE_SORT_J)
    jmp('srz_inner')
    a.label('srz_next_outer')
    inc32(RENDER_TREE_SORT_I)
    jmp('srz_outer')
    a.label('srz_done')
    print_label('render_tree_sort_msg')
    call('compute_render_tree_occlusion')
    a.emit(0xC3)

    a.label('compute_render_tree_occlusion')
    # Keep the occlusion pass as a real render-tree stage, but disable destructive culling for now.
    # The previous full-cover heuristic treated decorative SVG/text overlaps as covered nodes.
    store32(RENDER_TREE_OCC_COUNT,0)
    store32(RENDER_TREE_OCC_SCAN,0)
    a.label('cro_clear_loop')
    load32(RENDER_TREE_OCC_SCAN)
    a.emit(0x3B,0x05); a.emit(*(RENDER_TREE_COUNT).to_bytes(4,'little'))
    jae('cro_done')
    a.emit(0x89,0xC7)
    a.emit(0x6B,0xFF,RENDER_NODE_RECORD_SIZE)
    a.emit(0x81,0xC7); a.emit(*RENDER_TREE_BASE.to_bytes(4,'little'))
    a.emit(0x81,0x67,0x24); a.emit(*(0xFFFFFFFD).to_bytes(4,'little'))
    inc32(RENDER_TREE_OCC_SCAN)
    jmp('cro_clear_loop')
    a.label('cro_done')
    print_label('render_tree_occlusion_msg')
    a.emit(0xC3)

    a.label('lookup_render_node_for_current_dom')
    store32(RENDER_TREE_SCAN,0)
    a.label('lrn_loop')
    load32(RENDER_TREE_SCAN)
    a.emit(0x3B,0x05); a.emit(*(RENDER_TREE_COUNT).to_bytes(4,'little'))
    jae('lrn_not_found')
    a.emit(0x89,0xC7)
    a.emit(0x6B,0xFF,RENDER_NODE_RECORD_SIZE)
    a.emit(0x81,0xC7); a.emit(*RENDER_TREE_BASE.to_bytes(4,'little'))
    a.emit(0x8B,0x07)
    a.emit(0x3B,0x05); a.emit(*(ITER_INDEX).to_bytes(4,'little'))
    je('lrn_found')
    inc32(RENDER_TREE_SCAN)
    jmp('lrn_loop')
    a.label('lrn_found')
    a.emit(0x89,0x3D); a.emit(*(RENDER_NODE_PTR).to_bytes(4,'little'))
    a.emit(0xC3)
    a.label('lrn_not_found')
    store32(RENDER_NODE_PTR,0)
    a.emit(0xC3)

    a.label('render_node_intersects_dirty')
    # Returns EAX=1 if this is a full repaint or current render node intersects the mutation damage union.
    load32(DAMAGE_QUEUE_UNION_COUNT)
    a.emit(0x85,0xC0); jne('rnid_check')
    a.emit(0xB8); a.emit(*(1).to_bytes(4,'little'))
    a.emit(0xC3)
    a.label('rnid_check')
    a.emit(0x8B,0x3D); a.emit(*(RENDER_NODE_PTR).to_bytes(4,'little'))
    a.emit(0x85,0xFF); je('rnid_false')
    a.emit(0x8B,0x47,0x14)             # render.w
    a.emit(0x85,0xC0); je('rnid_false')
    a.emit(0x8B,0x47,0x18)             # render.h
    a.emit(0x85,0xC0); je('rnid_false')
    a.emit(0x8B,0x47,0x0C); a.emit(0x3B,0x05); a.emit(*(DIRTY_RECT_X2).to_bytes(4,'little')); jae('rnid_false')
    a.emit(0x8B,0x47,0x0C); a.emit(0x03,0x47,0x14); a.emit(0x3B,0x05); a.emit(*(DIRTY_RECT_X1).to_bytes(4,'little')); jbe('rnid_false')
    a.emit(0x8B,0x47,0x10); a.emit(0x3B,0x05); a.emit(*(DIRTY_RECT_Y2).to_bytes(4,'little')); jae('rnid_false')
    a.emit(0x8B,0x47,0x10); a.emit(0x03,0x47,0x18); a.emit(0x3B,0x05); a.emit(*(DIRTY_RECT_Y1).to_bytes(4,'little')); jbe('rnid_false')
    a.emit(0xB8); a.emit(*(1).to_bytes(4,'little'))
    a.emit(0xC3)
    a.label('rnid_false')
    a.emit(0x31,0xC0)
    a.emit(0xC3)

    # paint_dom_table is the only paint pass: parser builds nodes, this now walks DOM child lists.
    a.label('paint_dom_table')
    call('display_list_frame_begin')
    call('compositor_select_active_surface')
    call('build_render_tree_from_dom')
    store32(RENDER_NODE_VISIT_COUNT,0); store32(RENDER_NODE_CULL_COUNT,0)
    call('compositor_seed_dirty_from_invalidation')
    load32(DAMAGE_QUEUE_UNION_COUNT)
    a.emit(0x85,0xC0); jne('paint_dom_partial_damage')
    rect(0,0,320,200,13)
    rect(12,12,296,16,14)
    text('title',18,16,1,9)
    jmp('paint_dom_after_static')
    a.label('paint_dom_partial_damage')
    print_label('compositor_render_partial_msg')
    a.label('paint_dom_after_static')
    load32(DOM_PATCH_STATE)
    a.emit(0x85,0xC0); je('paint_dom_no_runtime_hidden_clear')
    rect(36,62,64,10,13)
    rect(36,80,66,18,13)
    rect(108,80,66,18,13)
    rect(180,80,66,18,13)
    rect(252,80,66,18,13)
    a.label('paint_dom_no_runtime_hidden_clear')
    call('paint_render_tree')            # compositor traversal is now driven by render nodes, not DOM child buckets
    call('display_list_frame_end')
    a.emit(0xC3)

    a.label('compositor_select_active_surface')
    call('device_resolve_framebuffer')
    load32(COMPOSITOR_SURFACE_COUNT)
    cmp_eax_imm(2)
    jne('compositor_bad')
    store32(COMPOSITOR_SCAN_PTR,SURFACE_OBJECT_BASE)
    store32(COMPOSITOR_TOP_Z,0)
    store32(COMPOSITOR_TOP_SURFACE,0)
    load32(SURFACE_SYSTEM_RECORD + 0x30)
    cmp_eax_imm(1)
    jne('compositor_bad')
    load32(SURFACE_AGENT_RECORD + 0x30)
    cmp_eax_imm(10)
    jne('compositor_bad')
    store32(COMPOSITOR_TOP_SURFACE,SURFACE_AGENT_RECORD)
    store32(COMPOSITOR_TOP_Z,10)
    print_label('compositor_scan_msg')
    print_label('compositor_zpick_msg')
    load32(COMPOSITOR_TOP_SURFACE)
    a.emit(0xA3); a.emit(*(COMPOSITOR_ACTIVE_SURFACE.to_bytes(4,'little')))
    load32(COMPOSITOR_ACTIVE_SURFACE)
    cmp_eax_imm(SURFACE_AGENT_RECORD)
    jne('compositor_bad')
    load32(COMPOSITOR_ACTIVE_SURFACE)
    a.emit(0x89,0xC7)
    a.emit(0x8B,0x07)
    cmp_eax_imm(SURFACE_TYPE_DOM)
    jne('compositor_bad')
    a.emit(0x8B,0x47,0x10)
    cmp_eax_imm(CAP_LIVE)
    jne('compositor_bad')
    print_label('compositor_select_msg')
    print_label('compositor_paint_route_msg')
    a.emit(0xC3)

    a.label('compositor_bad')
    print_label('compositor_bad_msg')
    jmp('halt')

    a.label('display_list_frame_begin')
    inc32(DISPLAY_LIST_FRAME_ID)
    store32(DISPLAY_LIST_FRAME_COMMANDS,0)
    store32(DISPLAY_LIST_FRAME_FLUSHES,0)
    store32(FRAME_DISPLAY_LIST_COUNT,0)
    store32(FRAME_DISPLAY_LIST_DRAWS,0)
    store32(FRAME_DIRTY_STATE,0)
    store32(DISPLAY_LIST_FRAME_STATE,1)
    print_label('display_list_frame_begin_msg')
    a.emit(0xC3)

    a.label('display_list_frame_end')
    # Drain any pending commands and close the compositor display-list frame transaction.
    load32(PAINT_CMD_COUNT)
    a.emit(0x85,0xC0); je('dlf_end_no_pending')
    call('flush_paint_command_buffer')
    a.label('dlf_end_no_pending')
    store32(DISPLAY_LIST_FRAME_STATE,0)
    call('flush_frame_display_list')
    print_label('display_list_frame_end_msg')
    a.emit(0xC3)

    a.label('paint_render_tree')
    # Walk compositor render nodes directly. DOM records are only payload pointers for text/style data.
    print_label('render_tree_traverse_msg')
    store32(RENDER_TREE_SCAN,0)
    a.label('prt_loop')
    load32(RENDER_TREE_SCAN)
    a.emit(0x3B,0x05); a.emit(*(RENDER_TREE_COUNT).to_bytes(4,'little'))
    jae('pdt_done')
    a.emit(0x89,0xC7)
    a.emit(0x6B,0xFF,RENDER_NODE_RECORD_SIZE)
    a.emit(0x81,0xC7); a.emit(*RENDER_TREE_BASE.to_bytes(4,'little'))
    a.emit(0x89,0x3D); a.emit(*(RENDER_NODE_PTR).to_bytes(4,'little'))
    a.emit(0x8B,0x47,0x24); a.emit(0x83,0xE0,0x02); a.emit(0x85,0xC0); jne('prt_occluded')
    a.emit(0x8B,0x07); a.emit(0xA3); a.emit(*(ITER_INDEX).to_bytes(4,'little'))
    a.emit(0x8B,0x47,0x04); a.emit(0xA3); a.emit(*(CURRENT_NODE_PTR).to_bytes(4,'little'))
    inc32(RENDER_NODE_VISIT_COUNT)
    call('render_node_intersects_dirty')
    a.emit(0x85,0xC0); jne('pdt_node_visible_dirty')
    inc32(RENDER_NODE_CULL_COUNT)
    jmp('pdt_next')
    a.label('prt_occluded')
    inc32(RENDER_NODE_CULL_COUNT)
    print_label('render_tree_occlusion_cull_msg')
    jmp('pdt_next')

    a.label('paint_parent_children')
    # Discover containers from hidden-tree sibling links, then paint their visible child buckets.
    load32(MAIN_NODE_ID)
    call('paint_hidden_children')
    load32(MAIN_NODE_ID); a.emit(0xA3); a.emit(*(CURRENT_PARENT_BUCKET_ID).to_bytes(4,'little'))
    call('paint_child_bucket')
    a.emit(0xC3)


    a.label('paint_hidden_children')
    a.emit(0x48)
    a.emit(0x6B,0xC0,0x18)
    a.emit(0x05); a.emit(*HIDDEN_DOM_BASE.to_bytes(4,'little'))
    a.emit(0x8B,0x40,0x0C)              # eax=first hidden child id
    a.emit(0xA3); a.emit(*(HIDDEN_TRAVERSAL_ID).to_bytes(4,'little'))
    a.label('phc_loop')
    load32(HIDDEN_TRAVERSAL_ID)
    a.emit(0x83,0xF8,0xFF)
    je('phc_done')
    a.emit(0xA3); a.emit(*(CURRENT_PARENT_BUCKET_ID).to_bytes(4,'little'))
    call('paint_child_bucket')
    load32(HIDDEN_TRAVERSAL_ID)
    a.emit(0x48)
    a.emit(0x6B,0xC0,0x18)
    a.emit(0x05); a.emit(*HIDDEN_DOM_BASE.to_bytes(4,'little'))
    a.emit(0x8B,0x40,0x10)              # next hidden sibling id
    a.emit(0xA3); a.emit(*(HIDDEN_TRAVERSAL_ID).to_bytes(4,'little'))
    jmp('phc_loop')
    a.label('phc_done')
    a.emit(0xC3)

    a.label('paint_child_bucket')
    load32(CURRENT_PARENT_BUCKET_ID)
    a.emit(0xC1,0xE0,0x03)
    a.emit(0x05); a.emit(*VISIBLE_CHILD_BUCKET_BASE.to_bytes(4,'little'))
    a.emit(0x8B,0x00)                   # eax=first visible child index
    a.emit(0xA3); a.emit(*(ITER_INDEX).to_bytes(4,'little'))
    a.label('pdt_loop')
    load32(ITER_INDEX)
    a.emit(0x83,0xF8,0xFF)
    je('pdt_done')
    a.emit(0x89,0xC7)                   # edi=index
    a.emit(0x6B,0xFF,0x30)              # *48
    a.emit(0x81,0xC7); a.emit(*VISIBLE_DOM_BASE.to_bytes(4,'little'))
    a.emit(0x89,0x3D); a.emit(*(CURRENT_NODE_PTR).to_bytes(4,'little')) # current node ptr
    call('lookup_render_node_for_current_dom')
    inc32(RENDER_NODE_VISIT_COUNT)
    call('render_node_intersects_dirty')
    a.emit(0x85,0xC0); jne('pdt_node_visible_dirty')
    inc32(RENDER_NODE_CULL_COUNT)
    jmp('pdt_next')
    a.label('pdt_node_visible_dirty')
    a.emit(0x8B,0x3D); a.emit(*(RENDER_NODE_PTR).to_bytes(4,'little'))
    a.emit(0x8B,0x47,0x08)              # eax=render_op from render tree; DOM is payload only
    a.emit(0x83,0xF8,0x01); je('pdt_button')
    a.emit(0x83,0xF8,0x02); je('pdt_h2')
    a.emit(0x83,0xF8,0x03); je('pdt_input')
    a.emit(0x83,0xF8,0x04); je('pdt_svg')
    a.emit(0x83,0xF8,0x05); je('pdt_banner')
    jmp('pdt_next')
    a.label('pdt_button')
    print_label('render_tree_dispatch_msg')
    a.emit(0x8B,0x3D); a.emit(*(CURRENT_NODE_PTR).to_bytes(4,'little'))
    a.emit(0x8B,0x47,0x20)              # parent id
    a.emit(0x3B,0x05); a.emit(*(FIRST_SECTION_ID).to_bytes(4,'little'))
    je('pdt_button_first_section')
    store32(PAINT_CMD_COUNT,0); store32(DIRTY_RECT_STATE,0); store32(DIRTY_RECT_COUNT,0); call('compositor_seed_dirty_from_invalidation')
    a.emit(0x8B,0x3D); a.emit(*(CURRENT_NODE_PTR).to_bytes(4,'little'))
    a.emit(0x8B,0x5F,0x0C)              # x
    a.emit(0x8B,0x57,0x10)              # y
    a.emit(0x8B,0x4F,0x14)              # w
    a.emit(0x8B,0x77,0x18)              # h
    a.emit(0x8B,0x47,0x1C)              # eax = DOM style/active color
    call('emit_paint_rect_command')
    a.emit(0x8B,0x3D); a.emit(*(CURRENT_NODE_PTR).to_bytes(4,'little'))
    a.emit(0x8B,0x5F,0x0C); a.emit(0x83,0xC3,0x04)
    a.emit(0x8B,0x57,0x10); a.emit(0x83,0xC2,0x04)
    a.emit(0xB9,0x04,0,0,0); a.emit(0xBE,0x04,0,0,0)
    a.emit(0xB8); a.emit(*(6).to_bytes(4,'little'))
