    a.emit(0x81,0xFA); a.emit(*(200).to_bytes(4,'little')); jae('fb_done')
    a.emit(0x89,0xCD)                  # ebp = requested width
    a.emit(0x89,0xDF)                  # edi = x
    a.emit(0x01,0xCF)                  # edi = x + w
    a.emit(0x81,0xFF); a.emit(*(320).to_bytes(4,'little'))
    jbe('fb_width_ok')
    a.emit(0xB9); a.emit(*(320).to_bytes(4,'little'))
    a.emit(0x29,0xD9)                  # ecx = 320 - x
    a.emit(0x89,0xCD)                  # ebp = clipped width
    a.label('fb_width_ok')
    a.emit(0x89,0xF7)                  # edi = h
    a.emit(0x01,0xD7)                  # edi = y + h
    a.emit(0x81,0xFF); a.emit(*(200).to_bytes(4,'little'))
    jbe('fb_height_ok')
    a.emit(0xBE); a.emit(*(200).to_bytes(4,'little'))
    a.emit(0x29,0xD6)                  # esi = 200 - y
    a.label('fb_height_ok')
