    a.emit(0x89,0x15); a.emit(*(TEXT_CURSOR_Y).to_bytes(4,'little'))
    a.emit(0xA3); a.emit(*(TEXT_COLOR).to_bytes(4,'little'))
    a.emit(0x89,0x35); a.emit(*(TEXT_PTR).to_bytes(4,'little'))
    a.label('dt_loop')
    a.emit(0x8B,0x35); a.emit(*(TEXT_PTR).to_bytes(4,'little'))
