    def elf32_phdr(p_offset: int, vaddr: int, paddr_offset: int, filesz: int, memsz: int, flags: int) -> bytes:
        paddr = paddr_offset
        return b''.join([
            (1).to_bytes(4, 'little'),                 # PT_LOAD
            p_offset.to_bytes(4, 'little'),
            vaddr.to_bytes(4, 'little'),              # p_vaddr
            paddr.to_bytes(4, 'little'),               # p_paddr: physical offset in this prototype
            filesz.to_bytes(4, 'little'),
            memsz.to_bytes(4, 'little'),
            flags.to_bytes(4, 'little'),
            (0x1000).to_bytes(4, 'little'),
        ])
    def elf32_image(entry: int, stack: int, req_or_cap: int, method: int, code: bytes, data: bytes, bss_len: int, data_offset: int = ELF32_DATA_OFFSET) -> bytes:
        phdrs = b''.join([
            elf32_phdr(ELF32_TEXT_OFFSET, ELF32_USER_TEXT, 0x80, len(code), len(code), 5),
            elf32_phdr(data_offset, ELF32_USER_DATA, 0x3000, len(data), len(data), 6),
            elf32_phdr(0, ELF32_USER_BSS, 0x3400, 0, bss_len, 6),
        ])
        ident = b'\x7fELF' + bytes([1, 1, 1, 0]) + bytes(8)
        header = b''.join([
            ident,
            (2).to_bytes(2, 'little'),                 # ET_EXEC
            (3).to_bytes(2, 'little'),                 # EM_386
            (1).to_bytes(4, 'little'),
            entry.to_bytes(4, 'little'),
            ELF32_PHDR_OFFSET.to_bytes(4, 'little'),
            (0).to_bytes(4, 'little'),
            (0).to_bytes(4, 'little'),
            ELF32_HEADER_SIZE.to_bytes(2, 'little'),
            ELF32_PHDR_SIZE.to_bytes(2, 'little'),
            ELF32_PHDR_COUNT.to_bytes(2, 'little'),
            (0).to_bytes(2, 'little'),
            (0).to_bytes(2, 'little'),
            (0).to_bytes(2, 'little'),
            phdrs,
        ])
        if len(header) > ELF32_TEXT_OFFSET:
            raise SystemExit('ELF32 header/phdr too large')
        note = b'FLUIDOS' + stack.to_bytes(4, 'little') + req_or_cap.to_bytes(4, 'little') + method.to_bytes(4, 'little')
        return header + bytes(ELF32_TEXT_OFFSET - len(header)) + code + bytes(data_offset - ELF32_TEXT_OFFSET - len(code)) + data + note
